def trimmed_mean(nums):
    if not nums:
        return None

    sorted_nums = sorted(nums)

    # Drop the minimum and maximum values
    trimmed_nums = sorted_nums[1:-1]

    if not trimmed_nums:
        return None  # Edge case: if there are less than 2 unique elements in the input list

    return sum(trimmed_nums) / len(trimmed_nums)
